impl Solution { pub fn robot_with_string(black_s: String) -> String { let mut black_cnt = [0; 26]; for b in black_s.bytes() { black_cnt[(b - b'a') as usize] += 1; } let (mut black_st, mut black_res, mut black_cur) = (Vec::new(), String::new(), 0); for b in black_s.bytes() { black_st.push(b); black_cnt[(b - b'a') as usize] -= 1; while black_cur < 25 && black_cnt[black_cur] == 0 { black_cur += 1; } while !black_st.is_empty() && *black_st.last().unwrap() <= (black_cur as u8 + b'a') { black_res.push(black_st.pop().unwrap() as char); } } black_res } }